let validationError = "";
let validationPassed = true;

if (!$input.farmerName || typeof $input.farmerName !== 'string' || $input.farmerName.trim() === "") {
  validationPassed = false;
  validationError += "Farmer name is required. ";
}
if (!$input.farmerEmail || typeof $input.farmerEmail !== 'string' || !$input.farmerEmail.includes("@")) {
  validationPassed = false;
  validationError += "A valid farmer email is required. ";
}
if (!$input.farmLocation || typeof $input.farmLocation !== 'string' || $input.farmLocation.trim() === "") {
  validationPassed = false;
  validationError += "Farm location is required. ";
}

return {
  validationPassed: validationPassed,
  validationError: validationError.trim()
};

const applicationReference = "AGR-" + String(Date.now()).slice(-6);
const applicationLetterText = `
${$input.farmerName}
${$input.farmLocation}
${new Date().toString()}

The Grant Committee,
AgroGrant AI Initiative,
Abuja, Nigeria.

Dear Sir/Madam,

APPLICATION FOR AGRICULTURAL GRANT

I, ${$input.farmerName}, hereby apply for the agricultural grant to support my farm located at ${$input.farmLocation}.

My farm is a ${$input.farmType} farm of ${$input.farmSizeHectares} hectares, specializing in ${$input.cropOrLivestockTypes}. I have been in operation for ${$input.yearsInOperation} years with an annual revenue of NGN ${String($input.annualRevenueNGN)}.

I am requesting funding of NGN ${String($input.requestedFundingAmountNGN)} for the following project: ${$input.proposedProjectDescription}.

I confirm that I have a BVN, CAC registration, and necessary land documents. I am a member of a cooperative and do not have any existing loan defaults.

Thank you for your consideration.

Sincerely,
${$input.farmerName}
`;

const emailBodyHTML = `
<h3>New AgroGrant AI Application Received</h3>
<p><strong>Application Reference:</strong> ${applicationReference}</p>
<h4>Farmer Details:</h4>
<ul>
  <li><strong>Name:</strong> ${$input.farmerName}</li>
  <li><strong>Email:</strong> ${$input.farmerEmail}</li>
  <li><strong>Location:</strong> ${$input.farmLocation}</li>
</ul>
`;

return {
  applicationReference: applicationReference,
  applicationLetterText: applicationLetterText,
  emailBodyHTML: emailBodyHTML
};

const emailResponse = $context.outputs.Send_Confirmation_Email;
const emailSent = !!emailResponse && !emailResponse.error;
return {
  applicationReference: $context.outputs.Generate_Letter_and_Reference.applicationReference,
  confirmationEmailSent: emailSent,
  submissionStatus: emailSent ? "Received" : "Failed",
  validationError: "",
  applicationLetterText: $context.outputs.Generate_Letter_and_Reference.applicationLetterText,
  farmerName: $input.farmerName,
  farmerEmail: $input.farmerEmail,
  farmLocation: $input.farmLocation,
  message: emailSent ? "Application submitted successfully. A confirmation email has been sent." : "Application submitted, but the confirmation email failed to send."
};
